head.script:
scwin.pos_groupCode = 0;  // 저장전 DataSet의 RowPosition을 저장 변수
scwin.userClsCd;
scwin.empNo;
scwin.loUpperLobranCd;
scwin.currentDate;
scwin.heavyEquipWorkIndicationRow = 0;

/**
 * event
 * @name onpageload
 * @description
 */
scwin.onpageload = function () {
    scwin.userClsCd = $c.data.getMemInfo("userClsCd") ?? "";    // 사용자구분코드(02:협력업체(운송))
    scwin.empNo = $c.data.getMemInfo("empNo") ?? "";
    scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd") ?? "";  // 물류상위점소코드
    scwin.currentDate = $c.date.getServerDateTime("yyyyMMdd");

    ed_wrkDt.setValue(scwin.currentDate);
    ed_wrkDt.focus();
    tbx_impExpClsCd.addClass("req");

    let codeOptions = [
        { grpCd: "SD060", compID: "lc_impExpClsCd" },
        { grpCd: "OP199", compID: "lc_tformWrkImpleKndCd" },
        { grpCd: "OP182", compID: "lc_pchsAdjmStdCd" },
        { grpCd: "OP911", compID: "lc_pchsAdptShiftCnt" },
        { grpCd: "OP270", compID: "lc_ctrlPchsPcostRsn" },
        { grpCd: "OP210", compID: "gr_heavyEquipNonOperationHour:nonoprtRsnCd" },
    ];
    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);

    codeOptions = [
        {
            method: "getLuxeComboDataNoSort",
            param1: "PsCommonEBC",
            param2: "retriveClntCdY",
            compID: "lc_oilStatCd"
        }
    ];
    $c.data.setGauceUtil(codeOptions);
};

/**
 * event
 * @name onUdcCompleted
 * @description
 */
scwin.onUdcCompleted = function () {
    scwin.f_switchObjMode(1);
};

/**
 * method
 * @name onLoadCommonCode
 * @description 공통코드 조회 콜백
 */
scwin.onLoadCommonCode = function () {
    $c.data.dataListFilter(dlt_commonCodeOP199, "fltrCd2 == '1'");
};

/**
 * event
 * @name f_qeryList
 * @description 본선작업진행현황
 */
scwin.f_qeryList = async function () {
    if (!await $c.gus.cfValidate([hd_eqCd, ed_eqCd, ed_wrkDt])) {	// 필수조건 : 중기코드, 작업일자
        return;
    }
    dma_condition.setJSON({
        "eqCd": hd_eqCd.getValue(),
        "wrkDt": ed_wrkDt.getValue(),
    });
    $c.sbm.execute(sbm_searchHeavyEquipWorkResults);
};

/**
 * event
 * @name f_save
 * @description 중기실적 저장
 */
scwin.f_save = async function () {
    if (!ds_heavyEquipWorkResults.getRowCount()) {
        return;
    }
    let isSupplyOil = false; /* 주유실적 등록 유무   */
    let isSupplyOilOnly = false;	/*주유실적만 등록한 경우 */
    let isModifyOil = false; /* 주유실적만 수정 유무 */

    let workResultsRow = gr_heavyEquipWorkResults.getFocusedRowIndex();
    let basisInfo = ds_heavyEquipBasisInformation.getRowJSON(0);

    if (!ds_heavyEquipWorkResults.getModifiedIndex().length
        && !ds_oilingResults.getModifiedIndex().length
        && !ds_heavyEquipBasisInformation.getModifiedIndex().length
        && !ds_heavyEquipNonOperationHour.getModifiedIndex().length) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["중기실적"]); // "@은(는) 변경된 사항이 없습니다."
        return;
    }

    let oiling = ds_oilingResults.getRowJSON(0);
    if (ds_oilingResults.getRowStatus(0) == "C") {
        // 주유 실적을 등록하는 경우(신규)   ==> 1: Insert
        if (oiling.oilStatCd != "" && oiling.oilingVol == 0) {
            await $c.gus.cfAlertMsg("주유 실적 등록시  주유량은 0보다 커야 합니다.");
            return;
        } else if (oiling.oilStatCd == "" && oiling.oilingVol != 0) {
            await $c.gus.cfAlertMsg("주유 실적 등록시  주유소는  필수입력항목 입니다.");
            return;
        } else {
            isSupplyOil = true;
        }

        //수정이 아니라 신규면 9998 flag
        ds_heavyEquipWorkResults.setCellData(workResultsRow, "oilingVol", 9998);
    } else if (ds_oilingResults.getRowStatus(0) == "U") {
        //주유실적만 수정된 경우
        if (lc_oilStatCd.getValue() == "" && (oiling.oilingVol == "0" || oiling.oilingVol == "")) {
            if (await $c.win.confirm("중기실적의 주유 내역을 삭제하시겠습니까?")) {
                ds_oilingResults.setCellData(0, "oilStatCd", "");
                ds_oilingResults.setCellData(0, "oilStatNm", "");
                ds_oilingResults.setCellData(0, "oilingVol", "");
                isModifyOil = true;
            }
        } else if (lc_oilStatCd.getValue() != "" && oiling.oilingVol == 0) {
            await $c.gus.cfAlertMsg("주유 실적 수정시  주유량은 0보다 커야 합니다.");
            return;
        } else if (lc_oilStatCd.getValue() == "" && oiling.oilingVol != 0) {
            await $c.gus.cfAlertMsg("주유 실적 수정시  주유소는  필수입력항목 입니다.");
            return;
        } else {
            isModifyOil = true;
        }
        if (ds_heavyEquipWorkResults.getRowStatus(0) == "R") {
            ds_heavyEquipWorkResults.setCellData(0, "oilingVol", 9999);
        }
    }

    // 검색조건 필수 입력 체크
    let workResults = ds_heavyEquipWorkResults.getAllJSON();
    let modifiedIdx = ds_heavyEquipWorkResults.getModifiedIndex();  //CUD 작업이 일어난 경우
    let iRowObj = null;
    let jRowObj = null;
    for (let i of modifiedIdx) {
        iRowObj = workResults[i];
        if (iRowObj.rowStatus == "C") { /* 1 : Insert*/
            for (let j = 0; j < workResults.length; j++) {
                jRowObj = workResults[j];
                if (i != j && iRowObj.wrkIndictNo == jRowObj.wrkIndictNo && iRowObj.eqCd == jRowObj.eqCd && iRowObj.impExpClsCd == jRowObj.impExpClsCd) {
                    await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터는 중복 데이터이므로 입력하실 수 없습니다.");
                    gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
                    return;
                }
            }
        }

        if (iRowObj.wrkIndictNo.trim() == "") {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업지시번호는 필수입력항목 입니다.");
            gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
            ed_wrkIndictNo.focus();
            return;
        }

        // 본선이면
        if (iRowObj.wrkIndictClsCd == "P") {
            if (iRowObj.impExpClsCd == "Y") {
                await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 수출입구분은 필수입력항목 입니다.");
                gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
                lc_impExpClsCd.focus();
                return;
            }
        }

        if (iRowObj.wrkStpCd.trim() == "") {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업단계는 필수입력항목 입니다.");
            gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
            lc_wrkStpCd.focus();
            return;
        }

        if (iRowObj.rowStatus == "D") {
            continue;
        }
        //삭제가 아닌 경우 ==> 2:삭제
        if (iRowObj.wrkStDt.trim() == "") {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업시작일자는 필수입력항목 입니다.");
            gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
            ed_wrkStDt.focus();
            return;
        }
        if (iRowObj.wrkStHh.trim() == "") {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업시작시간는 필수입력항목 입니다.");
            gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
            ed_wrkStHh.focus();
            return;
        }
        if (iRowObj.wrkEndDt.trim() == "") {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업종료일자는 필수입력항목 입니다.");
            gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
            ed_wrkEndDt.focus();
            return;
        }
        if (iRowObj.wrkEndHh.trim() == "") {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 작업종료시간는 필수입력항목 입니다.");
            gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
            ed_wrkEndHh.focus();
            return;
        }

        if (!await scwin.f_validateWrkTime(iRowObj)) {
            return false;
        }

        //작업시간이 겹치지 않도록 체크함
        for (let j = 0; j < workResults.length; j++) {
            jRowObj = workResults[j];
            if (jRowObj.rowStatus == "D" || j == i) {
                continue;
            }
            if (!((jRowObj.wrkStDt.trim() > iRowObj.wrkEndDt.trim() || (jRowObj.wrkStDt.trim() == iRowObj.wrkEndDt.trim() && jRowObj.wrkStHh.trim() >= iRowObj.wrkEndHh.trim())) ||
                (jRowObj.wrkEndDt.trim() < iRowObj.wrkStDt.trim() || (jRowObj.wrkEndDt.trim() == iRowObj.wrkStDt.trim() && jRowObj.wrkEndHh.trim() <= iRowObj.wrkStHh.trim())))) {
                await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적의 작업시간이 " + (j + 1) + "번째 의 작업시간과 중복됩니다.");
                gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
                ed_wrkStDt.focus();
                return;
            }
        }

        isSupplyOilOnly = false;
        //주유 실적만 등록하는 경우인지 Check 하는 부분.
        if ((isSupplyOil || isModifyOil) &&  // 주유 실적이 있고,
            iRowObj.pchsPcost == 0 &&          //매입원가
            iRowObj.ctrlPchsPcost == 0 &&      //조정원가
            iRowObj.tformEqPchsPcost == 0) {  //변형장비 원가
            isSupplyOilOnly = true; // 주유 실적만 등록하는 경우임.
        }

        // 자사가 아니면
        if (basisInfo.posnClsCd != 'J') {
            // 용차인 경우 실적 없이 주유 등록만 한 경우  매입거래처 등의 정보 없어도 되지만, 중기 실적 있으면 매입거래처등의 정보 Check 해야 함.
            if (!isSupplyOilOnly && iRowObj.pchsClntNo == "") {
                await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 매입거래처는 필수입력항목 입니다.");
                gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
                ed_pchsClntNo.focus();
                return;
            }

            // 용차인 경우 실적 없이 주유 등록만 한 경우  협력업체는  정보 없어도 되지만, 중기 실적 있으면 협력 업체는 정보 Check 해야 함.
            if (!isSupplyOilOnly && iRowObj.copCoClntNo == "") {
                await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 협력업체는 필수입력항목 입니다.");
                gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
                ed_copCoClntNo.focus();
                return;
            }
        }

        if (iRowObj.pchsDeptCd == "") {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 매입부서는 필수입력항목 입니다.");
            gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
            ed_pchsDeptCd.focus();
            return;
        }

        //  실적 없이 주유 등록만 한 경우  매입원가는  정보 없어도 되지만, 중기 실적 있으면 매입원가는  정보 Check 해야 함.
        if (!isSupplyOilOnly && iRowObj.pchsPcost == 0) {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 매입원가는 필수입력항목 입니다.");
            gr_heavyEquipWorkResults.setFocusedCell(i, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);;
            but_CalcPchsPcost.focus();
            return;
        }
        //  실적 없이 주유 등록만 한 경우 조정원가 Check 안하지만, 중기실적이 있는 경우는  조정금액이 있으면 조정사유 있어야 함.
        if (!isSupplyOilOnly && iRowObj.ctrlPchsPcost != 0 && iRowObj.ctrlPchsPcostRsn == "") {
            await $c.gus.cfAlertMsg((i + 1) + "번째 작업실적  데이터의 조정사유는 필수입력항목 입니다.");
            lc_ctrlPchsPcostRsn.focus();
            return;
        }
    }

    for (let i = 0; i < ds_heavyEquipNonOperationHour.getRowCount(); i++) {
        let rowObj = ds_heavyEquipNonOperationHour.getRowJSON(i);
        if (rowObj.nonoprtHhCnt == 0 && rowObj.nonoprtMintCnt == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["비가동시간"]);
            gr_heavyEquipNonOperationHour.setFocusedCell(i, "nonoprtHhCnt", true);
            return;
        }
        if (rowObj.nonoprtRsnCd == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["비가동사유"]);
            gr_heavyEquipNonOperationHour.setFocusedCell(i, "nonoprtRsnCd", true);
            return;
        }
    }

    if (cb_vsslCtrtYn.getValue() == "1" && ed_cvsslCtrtMgntNo.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["본선계약시 본선관리번호"]);
        ed_cvsslCtrtMgntNo.focus();
        return;
    }

    if (cb_vsslCtrtYn.getValue() == "1" && ed_wrkWt.getValue() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업톤수"]);
        ed_wrkWt.focus();
        return;
    }

    if (!await $c.win.confirm("저장하시겠습니까?")) {
        return;
    }

    let noRow = true;
    for (let i = 0; i < ds_heavyEquipWorkResults.getRowCount(); i++) {
        if (ds_heavyEquipWorkResults.getRowStatus(i) != "D") {
            noRow = false;
            break;
        }
    }
    if (noRow) {
        $c.data.deleteRow(ds_oilingResults, "Y");
    }

    scwin.pos_groupCode = workResultsRow;  // 저장 전의 위치 저장
    scwin.heavyEquipWorkIndicationRow = gr_heavyEquipWorkIndication.getFocusedRowIndex();
    ds_heavyEquipBasisInformation.modifyRowStatus(0, "C");
    ds_heavyEquipWorkIndication.modifyRowStatus(scwin.heavyEquipWorkIndicationRow, "C");
    ds_heavyEquipWorkResults.setCellData(workResultsRow, "regId", scwin.empNo);
    $c.sbm.execute(sbm_save);
};

/**
 * event
 * @name f_createHeavyEquipResultsData
 * @description 실적 데이터 기초생성
 */
scwin.f_createHeavyEquipResultsData = async function () {
    let basisInfo = ds_heavyEquipBasisInformation.getRowJSON(0);
    //실적 데이터 기초생성
    let v_checkYn = false; // 실적 데이터 기초생성시 작업시지사항 체크 유무
    for (let i = 0; i < ds_heavyEquipWorkIndication.getRowCount(); ++i) {
        if (ds_heavyEquipWorkIndication.getCellData(i, "chk") == "1") {
            ds_heavyEquipWorkIndication.setCellData(i, "pchsClntNo", basisInfo.logisHveqRepCopCoNo); //매입거래처
            ds_heavyEquipWorkIndication.setCellData(i, "copClntNo", basisInfo.clntNo); //협력업체
            v_checkYn = true;
            break;
        }
    }

    if (!v_checkYn) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["작업지시"]);
        return;
    }
    scwin.heavyEquipWorkIndicationRow = gr_heavyEquipWorkIndication.getFocusedRowIndex();
    $c.sbm.execute(sbm_CreateHeavyEquipResultsData);
};

/**
 * event
 * @name f_OnWrkIndictClsCdChanged
 * @description 콤보세팅
 */
scwin.f_OnWrkIndictClsCdChanged = async function (row) {
    //작업단계콤보 세팅
    if (ds_heavyEquipWorkResults.getCellData(row, "wrkIndictClsCd") == "P") {
        dma_RetrieveWorkStepList.setJSON({
            "upperWrkStpCd": "01",  //본선작업
            "lvl": "3",
            "wrkPlanTrgtYn": "1",
        });
        $c.gus.cfEnableBtnOnly([lc_impExpClsCd]);
        lc_impExpClsCd.options.mandatory = "true";
    } else {
        ds_heavyEquipWorkResults.setCellData(row, "impExpClsCd", "Y");
        dma_RetrieveWorkStepList.setJSON({
            "upperWrkStpCd": "03",  //장치장작업
            "lvl": "3",
            "wrkPlanTrgtYn": "1",
        });
        $c.gus.cfDisableObjects([lc_impExpClsCd]);
        lc_impExpClsCd.options.mandatory = "false";
    }
    scwin.f_cfRefreshMandSign();
    let e = await $c.sbm.execute(sbm_RetrieveWorkStepListCMD);
    scwin.sbm_RetrieveWorkStepListCMD_submitdone(e);

    //장비종류에 따른 필요장비규격콤보 세팅
    dma_retriveNesEqNrmList.setJSON({
        "sysCd": "DsCommonEBC",
        "queryId": "retriveNesEqNrmList",
        "param1": ds_heavyEquipBasisInformation.getCellData(0, "hveqKndCd"),
    });
    e = await $c.sbm.execute(sbm_retriveNesEqNrmList);
    scwin.sbm_retriveNesEqNrmList_submitdone(e);
};

/**
 * event
 * @name f_validateWrkTime
 * @description 작업시간 입력시 유효성체크
 */
scwin.f_validateWrkTime = async function (rowObj) {
    const nextDay = $c.date.addDate(ed_wrkDt.getValue(), 1);
    if (rowObj.shiftClsCd == 'D') {
        if (rowObj.wrkStDt.trim().length > 0 && rowObj.wrkStDt != ed_wrkDt.getValue()) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_030 + "작업일자와 같은날만 가능합니다", ["주간의 작업시작일자"]);
            ed_wrkStDt.focus();
            return false;
        }
    } else {
        if (rowObj.wrkStDt.trim().length > 0 && (rowObj.wrkStDt < ed_wrkDt.getValue() || rowObj.wrkStDt > nextDay)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_030 + "작업일자 하루이후까지만 가능합니다", ["야간/심야의 작업시작일자"]);
            ed_wrkStDt.focus();
            return false;
        }
        if (rowObj.wrkEndDt == nextDay) {
            if (rowObj.wrkEndHh.trim() > '0800') {
                await $c.gus.cfAlertMsg("야간/심야의 작업종료시간은 08시 이전이어야 합니다.");
                ed_wrkEndHh.focus();			// 시작시간에 focus
                return;
            }
        }
    }

    if (rowObj.wrkStDt.trim().length == 0 || rowObj.wrkEndDt.trim().length == 0) {
        return true;
    }

    if (rowObj.wrkStDt.trim().length != 8 || rowObj.wrkEndDt.trim().length != 8 || !$c.gus.cfIsAfterDate(rowObj.wrkStDt, rowObj.wrkEndDt, false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_wrkStDt.focus();
        return false;
    }

    if (rowObj.wrkStHh.trim().length == 0)
        return true;
    if (rowObj.wrkStHh.trim().length != 4) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["시간형식"]);
        ed_wrkStHh.focus();
        return false;
    }

    if (rowObj.wrkEndDt.trim().length > 0 && (rowObj.wrkEndDt < ed_wrkDt.getValue() || rowObj.wrkEndDt > nextDay)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_030 + "작업일자 하루이후까지만 가능합니다", ["종료일자"]);
        ed_wrkEndDt.focus();
        return false;
    }
    if (rowObj.wrkStDt.trim().length == 0 || rowObj.wrkEndDt.trim().length == 0)
        return true;

    if (rowObj.wrkStDt.trim().length != 8 || rowObj.wrkEndDt.trim().length != 8 || !$c.gus.cfIsAfterDate(rowObj.wrkStDt, rowObj.wrkEndDt, false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_wrkEndDt.focus();
        return false;
    }
    if (rowObj.wrkEndHh.trim().length == 0) {
        return true;
    }
    if (rowObj.wrkEndHh.trim().length != 4) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["시간형식"]);
        ed_wrkEndHh.focus();
        return false;
    }

    if (rowObj.wrkStHh.substring(0, 2) > "23") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_021, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
        ed_wrkStHh.focus();
        return;
    }
    if (rowObj.wrkStHh.substring(2, 4) > "59") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
        ed_wrkStHh.focus();
        return;
    }

    if (rowObj.wrkEndHh.substring(0, 2) > "24") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
        ed_wrkEndHh.focus();
        return;
    }
    if (rowObj.wrkEndHh.substring(0, 2) == "00" && rowObj.wrkEndHh.substring(2, 4) == "00") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
        ed_wrkEndHh.focus();
        return;
    }
    if (rowObj.wrkEndHh.substring(0, 2) == "24" && rowObj.wrkEndHh.substring(2, 4) > "00") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
        ed_wrkEndHh.focus();
        return;
    }
    if (rowObj.wrkEndHh.substring(2, 4) > "59") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
        ed_wrkEndHh.focus();
        return;
    }

    if (rowObj.wrkStDt.trim() == rowObj.wrkEndDt.trim() && rowObj.wrkStHh.trim() >= rowObj.wrkEndHh.trim()) {
        await $c.gus.cfAlertMsg("시작시간을 종료시간보다 작게 입력하여 주십시오.");
        ed_wrkStHh.focus();
        return false;
    }
    return true;
};

/**
 * event
 * @name f_CalcWrkTime
 * @description 작업시간계산
 */
scwin.f_CalcWrkTime = async function () {
    const wrkStDt = ed_wrkStDt.getValue().trim();
    const wrkStHh = ed_wrkStHh.getValue().trim();
    const wrkEndDt = ed_wrkEndDt.getValue().trim();
    const wrkEndHh = ed_wrkEndHh.getValue().trim();
    if (wrkStDt.length != 8 || wrkStHh.length != 4 || wrkEndDt.length != 8 || wrkEndHh.length != 4) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(wrkStDt, wrkEndDt, false) || wrkStDt == wrkEndDt && wrkStHh > wrkEndHh) {
        return;
    }

    let v_diff = 0;	//총시간차이
    const v_StHh = $c.num.parseInt(wrkStHh.substring(0, 2));   //시작시간
    const v_StMm = $c.num.parseInt(wrkStHh.substring(2, 4));   //시작분
    const v_EndHh = $c.num.parseInt(wrkEndHh.substring(0, 2)); //종료시간
    const v_EndMm = $c.num.parseInt(wrkEndHh.substring(2, 4)); //종료분

    let v_daysBetween = await scwin.cfDaysBetween(wrkStDt, wrkEndDt);
    if (v_daysBetween > 0) {
        // 날짜차이*24시간*60분 + (24시간*60분 - 시작시간*60분 + 시작분수) + (종료시간*60분 + 종료분수)
        v_diff = (v_daysBetween - 1) * 24 * 60 + (24 * 60 - v_StHh * 60 - v_StMm) + (v_EndHh * 60 + v_EndMm);
    } else {
        // 종료시간 - 시작시간
        v_diff = (v_EndHh * 60 + v_EndMm) - (v_StHh * 60 + v_StMm);
    }
    const v_diffHh = $c.num.parseInt(v_diff / 60); //시간차이
    const v_diffMm = $c.num.parseInt(v_diff % 60); //분차이

    ed_totInputHhCnt.setValue(v_diffHh);
    ed_totInputMintCnt.setValue(v_diffMm);

    scwin.f_CalcNonOperationHour();	//실가동시간도 같이 계산
};

/**
* method
* @name cfDaysBetween
* @description
*/
scwin.cfDaysBetween = async function (stDt, endDt) {
    let v_daysBetween = 0;
    if (!$c.date.isDate(stDt)) {
        await $c.win.alert("시작일자는 'YYYYMMDD' 형식이어야 합니다.");
    } else if (!$c.date.isDate(endDt)) {
        await $c.win.alert("종료일자는 'YYYYMMDD' 형식이어야 합니다.");
    } else {
        v_daysBetween = $c.date.diffDate(stDt, endDt);
    }
    return v_daysBetween;
};

