/**
 * event
 * @name f_DeleteRow
 * @description 행삭제
 */
scwin.f_DeleteRow = async function () {
    let row = gr_heavyEquipWorkResults.getFocusedRowIndex();
    let workResult = ds_heavyEquipWorkResults.getRowJSON(row);
    // 비가동 데이터셋부터 삭제한다
    for (let idx = 0; idx < ds_heavyEquipNonOperationHour.getRowCount(); idx++) {
        let rowObj = ds_heavyEquipNonOperationHour.getRowJSON(idx);
        if (rowObj.wrkIndictNo != workResult.wrkIndictNo || rowObj.eqCd != workResult.eqCd || rowObj.impExpClsCd != workResult.impExpClsCd) {
            continue;
        }
        if (rowObj.rowStatus == "C") {
            ds_heavyEquipNonOperationHour.removeRow(idx);
        } else {
            ds_heavyEquipNonOperationHour.deleteRow(idx);
        }
    }

    scwin.deleteMarked(gr_heavyEquipWorkResults, ds_heavyEquipWorkResults);
    let rowCnt = ds_heavyEquipWorkResults.getRowCount();
    tbx_totalRows2.setValue(rowCnt);
    if (row >= rowCnt) {
        row = 0;
    }
    if (rowCnt) {
        gr_heavyEquipWorkResults.setFocusedCell(row, gr_heavyEquipWorkResults.getFocusedColumnIndex() ?? 0, false);
    } else {
        ds_heavyEquipWorkResults.setRowPosition(null);
    }

    await scwin.f_switchObjMode(7);
};

