/**
 * event
 * @name f_CalcPchsPcost
 * @description 매입원가계산
 */
scwin.f_CalcPchsPcost = async function () {
    // 필수 입력 체크
    if (!await $c.gus.cfValidate([hd_eqCd, ed_eqCd, ed_wrkDt])) {
        return;
    }

    if ("H" == lc_pchsAdjmStdCd.getValue()) {			// 시간당
        if (ed_pchsAdptHhCnt.getValue() == "" && lc_pchsAdptMintCnt.getValue() == "") {
            await $c.gus.cfAlertMsg("하불임 적용시간을 입력하시오.");
            return;
        }

        if (ed_pchsAdptHhCnt.getValue() == 0 && lc_pchsAdptMintCnt.getValue() == 0) {
            await $c.gus.cfAlertMsg("하불임 적용시간을 입력하시오.");
            return;
        }
    } else if ("T" == lc_pchsAdjmStdCd.getValue()) {	// 톤당
        if (!await $c.gus.cfValidate([ed_wrkWt])) {
            return;
        }

        if (ed_wrkWt.getValue() < 1) {
            await $c.gus.cfAlertMsg("작업톤수를 입력하시오.");
            return;
        }
    } else if ("S" == lc_pchsAdjmStdCd.getValue()) {	// 쉬프트당
        if (lc_pchsAdptShiftCnt.getValue() == "") {
            await $c.gus.cfAlertMsg("하불임 적용쉬프트를 입력하시오.");
            return;
        }
    } else if ("" == lc_pchsAdjmStdCd.getValue()) {
        await $c.gus.cfAlertMsg("하불임계산기준을 입력하시오.");
        return;
    }

    if (!ds_heavyEquipBasisInformation.getRowCount()) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_008, ["중기정보"]);
        return;
    }

    let basisInfo = ds_heavyEquipBasisInformation.getRowJSON(0);
    let v_eqNrmCd = basisInfo.hveqNrmCd;
    let row = gr_heavyEquipWorkResults.getFocusedRowIndex();
    let rowObj = ds_heavyEquipWorkResults.getRowJSON(row);
    let v_clntNo = rowObj.copCoClntNo; //협력업체
    // 자사면 공통요율 사용
    if (basisInfo.posnClsCd == 'J') {
        v_clntNo = " ";
    } else {
        if (!await $c.gus.cfValidate([ed_copCoClntNo])) {
            //자사가 아닌경우 협력업체코드가 없으면 리턴
            return;
        }
    }

    // 조회 조건 DataSet에 입력
    dma_searchPchsPcost.setEmptyValue();
    dma_searchPchsPcost.setJSON({
        "lobranCd": basisInfo.lobranCd,
        "clntNo": v_clntNo,
        "eqKndCd": basisInfo.hveqKndCd,
        "eqNrmCd": lc_nesEqNrmCd.getValue() != "" ? lc_nesEqNrmCd.getValue() : v_eqNrmCd, //필요규격이 있으면 중기규격대신 필요규격사용
        "wrkUnitCd": lc_pchsAdjmStdCd.getValue(),
        "stDt": ed_wrkDt.getValue(),
    });

    // 조회 조건1 DataSet에 입력
    dma_searchPchsPcost1.setEmptyValue();
    dma_searchPchsPcost1.setJSON(rowObj);
    $c.sbm.execute(sbm_searchPchsPcost);
};

/**
 * event
 * @name f_openCommonPopUp
 * @description 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
 */
scwin.f_openCommonPopUp = async function (disGubun, pWinCloseTF) {
    // 선언부
    let sWinCloseTF = (pWinCloseTF == null) ? "T" : pWinCloseTF;
    let rtnList = null;  // 공통POP-UP -> 요청화면
    let pCode = "";
    let pName = "";
    let arrParam = null;
    let pLobranCd = "";
    let pLobranNm = "";
    if (ds_heavyEquipWorkIndication.getRowCount()) {
        let row = gr_heavyEquipWorkIndication.getFocusedRowIndex();
        pLobranCd = ds_heavyEquipWorkIndication.getCellData(row, "lobranCd"); //점소코드
        pLobranNm = ds_heavyEquipWorkIndication.getCellData(row, "lobranNm"); //점소명
    }
    let options = null;
    let workResultsRow = null;
    let drvStaffArr = [];
    let pWrkIndictNo = "";
    drvStaffArr[4] = { codeObj: ed_drvStaffNo1, nameObj: ed_drvStaffNm1 };
    drvStaffArr[5] = { codeObj: ed_drvStaffNo2, nameObj: ed_drvStaffNm2 };
    drvStaffArr[6] = { codeObj: ed_drvStaffNo3, nameObj: ed_drvStaffNm3 };

    switch (disGubun) {
        case 1:
            // 중기 팝업
            pCode = ed_eqCd.getValue().replace(/\s*$/, '');	// 중기코드
            pDate = ed_wrkDt.getValue();						// 작업일자
            hd_eqCd.setValue("");	//중기코드
            ed_eqCd.setValue("");	//중기단축코드
            ed_eqNm.setValue("");	//중기명

            arrParam = new Array();
            arrParam[0] = "";    				//assgnLobranCd점소코드
            arrParam[1] = ""; 					//eqKndCd중기종류
            arrParam[2] = "";					//clntCd거래처코드
            arrParam[3] = pDate;   				//usblDt작업계획일자
            arrParam[4] = pCode;		  		//eqNo
            arrParam[5] = "";					//eqNm
            arrParam[6] = sWinCloseTF;	//T,F구분
            arrParam[7] = 'T';	//T,F구분

            let opts = {
                id: "op_101_01_12p_popup",
                popupName: "중기조회",
                modal: true,
                type: "browserPopup",  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
                width: 1050,
                height: 550,
            };

            rtnList = await $c.win.openPopup("/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml", opts, arrParam);
            if (rtnList != null && rtnList[0] != "N/A" && rtnList[0] != "undefind" && rtnList.length > 0) {
                hd_eqCd.setValue(rtnList[12]);	//중기코드
                ed_eqCd.setValue(rtnList[0]);	//중기단축코드
                if (rtnList[1] == "undefind" || rtnList[1].trim() == null || rtnList[1].trim() == "") {
                    ed_eqNm.setValue(rtnList[2]);	//중기명
                } else {
                    ed_eqNm.setValue(rtnList[1]);	//중기번호
                }
            } else {
                hd_eqCd.setValue("");	//중기코드
                ed_eqCd.setValue("");	//중기단축코드
                ed_eqNm.setValue("");	//중기명
            }
            break;

        case 2:
            //매입거래처
            pCode = ed_pchsClntNo.getValue().replace(/\s*$/, '');
            pName = ed_pchsClntNm.getValue();
            udc_pchsClnt.cfCommonPopUp(scwin.udc_pchsClnt_popup_callback,
                pCode,							//pCode
                pName,							//pName
