/**
 * method
 * @name udc_copCoClnt_popup_callback
 * @description 협력업체 공통코드팝업 콜백 함수
 */
scwin.udc_copCoClnt_popup_callback = function (rtnList) {
    if (rtnList == null) {  // 팝업을 X 버튼으로 닫았을 때
        rtnList = new Array();
        let listLength = 2;
        for (let k = 0; k < listLength; k++) {
            rtnList[k] = "";
        }
    } else if (rtnList[0] == "N/A") { // 팝업창 아래의 '닫기' 버튼으로 닫았을 때
        $c.gus.cfSetValue(ed_copCoClntNo, $c.gus.cfGetHiddenValue(ed_copCoClntNo));
        $c.gus.cfSetValue(ed_copCoClntNm, $c.gus.cfGetHiddenValue(ed_copCoClntNm));
        return;
    }

    $c.gus.cfSetValue(ed_copCoClntNo, rtnList[0]);
    $c.gus.cfSetHiddenValue(ed_copCoClntNo, rtnList[0]);

    $c.gus.cfSetValue(ed_copCoClntNm, rtnList[1]);
    $c.gus.cfSetHiddenValue(ed_copCoClntNm, rtnList[1]);

    ed_pchsPcost.setValue("0"); //매입원가
};

