/**
 * event
 * @name f_registrationPopUp
 * @description 중기실적 일괄등록
 */
scwin.f_registrationPopUp = async function () {
    //op_306_01_25p 화면은 삭제된 화면, 화면열기 기능 막음
    return;
    let condition = dma_condition.getJSON();
    if (condition.eqCd != hd_eqCd.getValue() || condition.wrkDt != ed_wrkDt.getValue() || !ds_heavyEquipWorkResults.getRowCount()) {
        await $c.gus.cfAlertMsg("일괄등록할 실적이 없습니다.");
        return;
    }

    if (ed_pchsPcost.getValue() == 0) {
        await $c.gus.cfAlertMsg("기본실적의 매입원가가 없습니다..");
        return;
    }

    if (!await $c.gus.cfValidate([ed_pchsDeptCd])) {
        await $c.gus.cfAlertMsg("기본실적의 매입부서가 없습니다..");
        return;
    }

    let workResults = ds_heavyEquipWorkResults.getRowJSON(gr_heavyEquipWorkResults.getFocusedRowIndex());
    let workIndication = ds_heavyEquipWorkIndication.getRowJSON(gr_heavyEquipWorkIndication.getFocusedRowIndex());
    let args = new Array();
    args[0] = condition.eqCd; // 중기코드
    args[1] = condition.wrkDt; // 작업일자
    args[2] = workResults.wrkIndictNo; // 작업지시번호
    args[3] = workResults.impExpClsCd; // 수출입구분코드
    args[4] = workResults.pchsAdjmStdCd; // 하불임계산기준
    args[5] = workIndication.lobranCd; //점소코드
    args[6] = workIndication.lobranNm; //점소명

    let opts = {
        id: "op_306_01_25p_popup",
        popupName: "중기실적일괄등록",
        modal: true,
        type: "browserPopup",  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        title: "op_306_01_25p pop",  //Layer pop
        width: 900,
        height: 600,
    };
    await $c.win.openPopup("/ui/ds/op/wrkrslts/stvwrkrslts/op_306_01_25p.xml", opts, args);

    await scwin.f_qeryList();	// 투입중기 리스트 PopUp Close 시 List Reload
};

/**
 * event
 * @name f_CalcNonOperationHour
 * @description 비가동시간계산
 */
scwin.f_CalcNonOperationHour = function () {
    if (!ds_heavyEquipWorkResults.getRowCount()) {
        return;
    }

    let rowObj = ds_heavyEquipWorkResults.getRowJSON(gr_heavyEquipWorkResults.getFocusedRowIndex());
    let v_totInputHhCnt = $c.num.parseInt(ed_totInputHhCnt.getValue(), 0);	//가동시간
    let v_totInputMintCnt = $c.num.parseInt(ed_totInputMintCnt.getValue(), 0);	//가동분
    let v_NonOperationHh = 0;	//비가동시간
    let v_NonOperationMm = 0;	//비가동분
    let v_diff = v_totInputHhCnt * 60 + v_totInputMintCnt;    //총차이
    if (ds_heavyEquipNonOperationHour.getRowCount()) {
        let allData = ds_heavyEquipNonOperationHour.getAllFilteredJSON();
        for (let item of allData) {
            if (item.wrkIndictNo == rowObj.wrkIndictNo && item.eqCd == rowObj.eqCd && item.impExpClsCd == rowObj.impExpClsCd && rowObj.rowStatus != "D") {
                if (item.nonoprtHhCnt != "") {
                    v_NonOperationHh += $c.num.parseInt(item.nonoprtHhCnt);
                }
                if (item.nonoprtMintCnt != "") {
                    v_NonOperationMm += $c.num.parseInt(item.nonoprtMintCnt);
                }
            }
        }

        // 총투입시간 - 비가동시간
        v_diff = (v_totInputHhCnt * 60 + v_totInputMintCnt) - (v_NonOperationHh * 60 + v_NonOperationMm);
    }

    if (cb_mealYn.getValue() == "1") {
        v_diff = v_diff - 60;
    }

    let v_diffHh = $c.num.parseInt(v_diff / 60);   //시간차이
    let v_diffMm = $c.num.parseInt(v_diff % 60);   //분차이

    ed_realOprtHhCnt.setValue(v_diffHh);
    ed_realOprtMintCnt.setValue(v_diffMm);
};

/**
 * event
 * @name f_chkOpenCommonPopupText
 * @description TEXT BOX 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 */
scwin.f_chkOpenCommonPopupText = async function (inObj, codeObj, disGubun) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우
    if (inObj.getValue().trim() == "" || inObj.getReadOnly()) {
        return;
    }

    codeObj.setValue("");
    await scwin.f_openCommonPopUp(disGubun);
};

/**
 * event
 * @name f_chkOpenCommonPopupEmedit
 * @description EMEDIT 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 */
scwin.f_chkOpenCommonPopupEmedit = async function (inObj, chkObj, txtObj, disGubun) {
    let objValue = inObj.getValue().replace(/^\s*/, '');
    if (txtObj != null) {
        txtObj.setValue("");
    }

    // 값이 입력이 안된 경우  팝업을 실행하지 않음.
    if (objValue == "" || objValue == null) {
        inObj.setValue("");
        if (chkObj != null) {
            chkObj.setValue("");
        }
        return;
    }

    // 해당 EMEDIT가 Disable 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (inObj.getReadOnly() || inObj.getDisabled() || chkObj?.getValue() == objValue) {
        return;
    }

    await scwin.f_openCommonPopUp(disGubun);
};

/**
 * event
 * @name f_switchObjMode
 * @description 화면구성요소 제어(버튼 입력박스등등 disable, enable)
 */
scwin.f_switchObjMode = async function (gubun) {
    switch (gubun) {
        case 1:	//화면로딩
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtn([btn_InitDataCreate, btn_InitDataRegistration]);
            $c.gus.cfDisableObjects([btn_wrkIndictNo, btn_pchsClntNo, btn_copCoClntNo, btn_pchsDeptCd, btn_drvStaffNo1, btn_drvStaffNo2, btn_drvStaffNo3, ed_prtgCost, ed_pchsDeptCd, ed_pchsPcost, ed_cvsslCtrtMgntNo, btn_cvsslCtrtMgntNo, ed_wrkCommCd, ed_wrkCommNm, btn_wrkCommCd]);
            break;

        case 2:	//조회버튼클릭
            break;

        case 3:	//신규
            break;

        case 4:	//수정
            await scwin.f_switchObjMode(1);

            $c.gus.cfEnableKeyData();
            $c.gus.cfDisableKey();
            $c.gus.cfEnableBtnOnly([btn_InitDataCreate, btn_InitDataRegistration, btn_Save]);
            $c.gus.cfEnableObjects([btn_pchsClntNo, btn_copCoClntNo, btn_pchsDeptCd, btn_drvStaffNo1, btn_drvStaffNo2, btn_drvStaffNo3, ed_prtgCost, ed_pchsDeptCd]);

            if (ds_heavyEquipWorkResults.getRowStatus(gr_heavyEquipWorkResults.getFocusedRowIndex()) == "C") {
                $c.gus.cfEnableObjects([btn_wrkIndictNo, lc_impExpClsCd]);
            }

            if (ds_heavyEquipBasisInformation.getRowCount()) {
                let basisInfo = ds_heavyEquipBasisInformation.getRowJSON(0);
                if (basisInfo.posnClsCd == 'J') {
                    $c.gus.cfEnableBtnOnly([but_CalcPchsPcost]);
                    ed_pchsPcost.options.mandatory = "true";
                    lc_pchsAdjmStdCd.options.mandatory = "true";
                    ed_copCoClntNo.options.mandatory = "false";
                    ed_pchsClntNo.options.mandatory = "false";
                    if ("H" == lc_pchsAdjmStdCd.getValue()) {			// 시간당
                        ed_pchsAdptHhCnt.options.mandatory = "true"; // 시간당일 경우 하불임 적용시간 필수
                        lc_pchsAdptMintCnt.options.mandatory = "true";
                        ed_wrkWt.options.mandatory = "false";
                        lc_pchsAdptShiftCnt.options.mandatory = "false";
                    } else if ("T" == lc_pchsAdjmStdCd.getValue()) {	// 톤당
                        ed_pchsAdptHhCnt.options.mandatory = "false";
                        lc_pchsAdptMintCnt.options.mandatory = "false";
                        lc_pchsAdptShiftCnt.options.mandatory = "false";
                        ed_wrkWt.options.mandatory = "true";			// 톤당일 경우 작업톤수 필수
                    } else if ("S" == lc_pchsAdjmStdCd.getValue()) {	// 쉬프트당
                        ed_pchsAdptHhCnt.options.mandatory = "false";
                        lc_pchsAdptMintCnt.options.mandatory = "false";
                        ed_wrkWt.options.mandatory = "false";
                        lc_pchsAdptShiftCnt.options.mandatory = "true";
                    } else {
                        ed_pchsAdptHhCnt.options.mandatory = "false";
                        lc_pchsAdptMintCnt.options.mandatory = "false";
                        ed_wrkWt.options.mandatory = "false";
                    }
                } else {
                    $c.gus.cfEnableBtnOnly([but_CalcPchsPcost]);
                    ed_pchsPcost.options.mandatory = "true";
                    lc_pchsAdjmStdCd.options.mandatory = "true";
                    ed_copCoClntNo.options.mandatory = "true";
                    ed_pchsClntNo.options.mandatory = "true";
                    if ("H" == lc_pchsAdjmStdCd.getValue()) {			// 시간당
                        ed_pchsAdptHhCnt.options.mandatory = "true";	// 시간당일 경우 하불임 적용시간 필수
                        lc_pchsAdptMintCnt.options.mandatory = "true";
                        ed_wrkWt.options.mandatory = "false";
                    } else if ("T" == lc_pchsAdjmStdCd.getValue()) {	// 톤당
                        ed_pchsAdptHhCnt.options.mandatory = "false";
                        lc_pchsAdptMintCnt.options.mandatory = "false";
                        ed_wrkWt.options.mandatory = "true";			// 톤당일 경우 작업톤수 필수
                    } else if ("S" == lc_pchsAdjmStdCd.getValue()) {	// 쉬프트당
                        ed_pchsAdptHhCnt.options.mandatory = "false";  // 쉬프트당일 경우 하불임 적용시간 필수
                        lc_pchsAdptMintCnt.options.mandatory = "false";
                        ed_wrkWt.options.mandatory = "false";
                        lc_pchsAdptShiftCnt.options.mandatory = "true";
                    } else {
                        ed_pchsAdptHhCnt.options.mandatory = "false";
                        lc_pchsAdptMintCnt.options.mandatory = "false";
                        ed_wrkWt.options.mandatory = "false";
                    }
                }
                $c.gus.cfDisableObjects([ed_pchsPcost, ed_cvsslCtrtMgntNo, ed_wrkCommCd, ed_wrkCommNm]);
            }
            //조정매입원가에 따른 조정사유 필수표시
            if (ed_ctrlPchsPcost.getValue() > 0) {
                lc_ctrlPchsPcostRsn.options.mandatory = "true";
            } else {
                lc_ctrlPchsPcostRsn.options.mandatory = "false";
            }
            scwin.f_cfRefreshMandSign();
            break;

        case 5:	//조회완료
            if (ds_heavyEquipBasisInformation.getRowCount()) {
                $c.gus.cfEnableBtnOnly([btn_InitDataCreate, btn_Save]);
            }
            if (ds_heavyEquipWorkResults.getRowCount()) {
                $c.gus.cfEnableBtnOnly([btn_InitDataRegistration]);
                await scwin.f_switchObjMode(4);
            }
            $c.gus.cfDisableObjects([ed_pchsPcost, ed_cvsslCtrtMgntNo, ed_wrkCommCd, ed_wrkCommNm]);
            break;

        case 6:	//수정불가
            break;

        case 7: //행삭제, 취소
            if (!ds_heavyEquipWorkResults.getRowCount()) {
                await scwin.f_switchObjMode(1);
            } else {
                await scwin.f_switchObjMode(4);
            }
            break;

        case 8:	//행추가
            $c.gus.cfEnableKeyData();
            $c.gus.cfEnableObjects([btn_wrkIndictNo, btn_pchsClntNo, btn_copCoClntNo, btn_pchsDeptCd, btn_drvStaffNo1, btn_drvStaffNo2, btn_drvStaffNo3, ed_prtgCost, ed_pchsDeptCd]);
            $c.gus.cfDisableObjects([ed_pchsPcost, ed_cvsslCtrtMgntNo, ed_wrkCommCd, ed_wrkCommNm]);
            await scwin.f_OnWrkIndictClsCdChanged(gr_heavyEquipWorkResults.getFocusedRowIndex());
            break;

        default:
            break;
    }
    if (scwin.userClsCd != "01") {//  내부사용자가 아니면
        $c.gus.cfDisableObjects([ed_copCoClntNo, ed_copCoClntNm, btn_copCoClntNo]);  //협력업체
    }
};

/**
 * event
 * @name f_onFocusCall
 * @description 하불임 계산기준에 따른 기준값 변경 시 기존 Data Backup
 */
scwin.f_onFocusCall = function () {
    if (lc_pchsAdjmStdCd.getValue() == "H") {			// 시간당
        ed_check.setValue(ed_pchsAdptHhCnt.getValue());
        ed_check.setValue(lc_pchsAdptMintCnt.getValue());
    } else if (lc_pchsAdjmStdCd.getValue() == "T") {	// 톤당
        ed_check.setValue(ed_wrkWt.getValue());
    } else if (lc_pchsAdjmStdCd.getValue() == "S") {  // 쉬프트당
        ed_check.setValue(lc_pchsAdptShiftCnt.getValue());
    }
};

/**
 * event
 * @name f_outFocusCall
 * @description 하불임 계산기준에 따른 기준값 변경 시 Data 초기화
 */
scwin.f_outFocusCall = function () {
    if (lc_pchsAdjmStdCd.getValue() == "H") {			// 하불임 계산기준 - 시간당
        if (ed_check.getValue() != ed_pchsAdptHhCnt.getValue() || ed_check.getValue() != lc_pchsAdptMintCnt.getValue()) {
            ed_pchsPcost.setValue("0");
            ed_check.setValue("");
        }
    } else if (lc_pchsAdjmStdCd.getValue() == "T") {	// 하불임 계산기준 - 톤당
        if (ed_check.getValue() != ed_wrkWt.getValue()) {
            ed_pchsPcost.setValue("0");
            ed_check.setValue("");
        }
    } else if (lc_pchsAdjmStdCd.getValue() == "S") {			// 하불임 계산기준 - 시간당
        if (ed_check.getValue() != ed_pchsAdptHhCnt.getValue() || ed_check.getValue() != lc_pchsAdptMintCnt.getValue() || ed_check.getValue() != lc_pchsAdptShiftCnt.getValue()) {
            ed_pchsPcost.setValue("0");
            ed_check.setValue("");
        }
    }
};

/**
 * event
 * @name f_pchsAdjmStdCdOnFocusCall
 * @description 하불임 계산기준 변경 시 기존 Data Backup
 */
scwin.f_pchsAdjmStdCdOnFocusCall = function () {
    ed_check.setValue(lc_pchsAdjmStdCd.getValue());
};

/**
 * event
 * @name f_pchsAdjmStdCdOutFocusCall
 * @description 하불임 계산기준 변경 시 Data 초기화
 */
scwin.f_pchsAdjmStdCdOutFocusCall = function () {
    if (lc_pchsAdjmStdCd.getValue() != ed_check.getValue()) {			// 시간당
        ed_pchsPcost.setValue("0");
        ed_check.setValue("");
    }

    if ("H" == lc_pchsAdjmStdCd.getValue()) {			// 시간당
        ed_pchsAdptHhCnt.options.mandatory = "true";	// 시간당일 경우 하불임 적용시간 필수
        lc_pchsAdptMintCnt.options.mandatory = "true";
        lc_pchsAdptShiftCnt.options.mandatory = "false";
        ed_wrkWt.options.mandatory = "false";
    } else if ("T" == lc_pchsAdjmStdCd.getValue()) {	// 톤당
        ed_pchsAdptHhCnt.options.mandatory = "false";
        lc_pchsAdptShiftCnt.options.mandatory = "false";
        lc_pchsAdptMintCnt.options.mandatory = "false";
        ed_wrkWt.options.mandatory = "true";			// 톤당일 경우 작업톤수 필수
    } else if ("S" == lc_pchsAdjmStdCd.getValue()) {	// 쉬프트당
        ed_pchsAdptHhCnt.options.mandatory = "false"; // 쉬프트당일 경우 하불임 적용시간 필수
        lc_pchsAdptMintCnt.options.mandatory = "false";
        lc_pchsAdptShiftCnt.options.mandatory = "true";
        ed_wrkWt.options.mandatory = "false";
    }

    scwin.f_cfRefreshMandSign();
};

