/**
 * event
 * @name gr_heavyEquipWorkResults_onviewchange
 * @description
 */
scwin.gr_heavyEquipWorkResults_onbeforeedit = function (row, col, value) {
    let colid = gr_heavyEquipWorkResults.getColumnID(col);
    if (colid !== "wrkIndictClsCd") {
        return;
    }
    scwin.wrkIndictClsCdInfo = {
        "row": row,
        "col": col,
        "value": value,
    };
};

/**
 * event
 * @name gr_heavyEquipWorkResults_onafteredit
 * @description
 */
scwin.gr_heavyEquipWorkResults_onafteredit = function (row, col, value) {
    let colid = gr_heavyEquipWorkResults.getColumnID(col);
    if (colid !== "wrkIndictClsCd" || scwin.wrkIndictClsCdInfo?.col !== col || scwin.wrkIndictClsCdInfo?.row !== row) {
        return;
    }
    if (value !== "P" && value !== "Y" && value !== "T" && scwin.wrkIndictClsCdInfo.value !== value) {
        ds_heavyEquipWorkResults.setCellData(row, colid, scwin.wrkIndictClsCdInfo.value);
    }
};

/**
 * event
 * @name gr_heavyEquipNonOperationHour_onafteredit
 * @description
 */
scwin.gr_heavyEquipNonOperationHour_onafteredit = async function (row, col, value) {
    let colid = gr_heavyEquipNonOperationHour.getColumnID(col);
    switch (colid) {
        case "nonoprtHhCnt":
            break;

        case "nonoprtMintCnt":  // 분 입력 체크
            if (value >= 60) {
                ds_heavyEquipNonOperationHour.setCellData(row, colid, 0);
                await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["비가동시간"]);
                return;
            }
            break;

        default:
            return;
    }

    if (value === "") {
        ds_heavyEquipNonOperationHour.setCellData(row, colid, "0");
    }

    let rowObj = ds_heavyEquipNonOperationHour.getRowJSON(row);
    // 총투입시간과 비교 체크
    if ($c.num.parseInt(rowObj.nonoprtHhCnt) > $c.num.parseInt(ed_totInputHhCnt.getValue()) ||
        ($c.num.parseInt(rowObj.nonoprtHhCnt) == $c.num.parseInt(ed_totInputHhCnt.getValue()) && $c.num.parseInt(rowObj.nonoprtMintCnt) > $c.num.parseInt(ed_totInputMintCnt.getValue()))) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["비가동시간", "총 투입시간"]);
        ds_heavyEquipNonOperationHour.setCellData(row, "nonoprtHhCnt", 0);
        ds_heavyEquipNonOperationHour.setCellData(row, "nonoprtMintCnt", 0);
        return;
    }

    scwin.f_CalcNonOperationHour();
};

/**
 * event
 * @name ds_heavyEquipWorkResults_onbeforerowpositionchange
 * @description
 */
scwin.ds_heavyEquipWorkResults_onbeforerowpositionchange = function (info) {
    if (ds_heavyEquipWorkResults.getRowStatus(info.newRowIndex) == "C") {
        scwin.f_switchObjMode(8);
    }
    return true;
};

/**
 * event
 * @name setHeavyEquipWorkResultsFilter
 * @description
 */
scwin.setHeavyEquipWorkResultsFilter = function () {
    ds_heavyEquipWorkResults.clearFilter();
    let row = gr_heavyEquipWorkIndication.getFocusedRowIndex();
    if (row >= 0) {
        let rowObj = ds_heavyEquipWorkIndication.getRowJSON(row);
        ds_heavyEquipWorkResults.setColumnFilter({ type: 'row', colIndex: 'wrkIndictNo', key: rowObj.wrkIndictNo, condition: 'and', exactMatch: true });
        ds_heavyEquipWorkResults.setColumnFilter({ type: 'row', colIndex: 'impExpClsCd', key: rowObj.impExpClsCd, condition: 'and', exactMatch: true });
    }
    tbx_totalRows2.setValue(ds_heavyEquipWorkResults.getRowCount());
};

/**
 * event
 * @name setheavyEquipNonOperationHourFilter
 * @description
 */
scwin.setheavyEquipNonOperationHourFilter = function () {
    ds_heavyEquipNonOperationHour.clearFilter();
    let row = gr_heavyEquipWorkResults.getFocusedRowIndex();
    if (row >= 0) {
        let rowObj = ds_heavyEquipWorkResults.getRowJSON(gr_heavyEquipWorkResults.getFocusedRowIndex());
        ds_heavyEquipNonOperationHour.setColumnFilter({ type: 'row', colIndex: 'wrkIndictNo', key: rowObj.wrkIndictNo, condition: 'and', exactMatch: true });
        ds_heavyEquipNonOperationHour.setColumnFilter({ type: 'row', colIndex: 'eqCd', key: rowObj.eqCd, condition: 'and', exactMatch: true });
        ds_heavyEquipNonOperationHour.setColumnFilter({ type: 'row', colIndex: 'impExpClsCd', key: rowObj.impExpClsCd, condition: 'and', exactMatch: true });
    }
    let rowCnt = ds_heavyEquipNonOperationHour.getRowCount();
    tbx_totalRows3.setValue(rowCnt);
    if (rowCnt) {
        gr_heavyEquipNonOperationHour.setFocusedCell(0, 0, false);
    }
};

