            case "0":
                ed_pchsAdptHhCnt.setValue("0");
                break;

            case "1":
                ed_pchsAdptHhCnt.setValue("8");
                break;

            case "2":
                ed_pchsAdptHhCnt.setValue("4");
                break;

            case "3":
                ed_pchsAdptHhCnt.setValue("5");
                break;
        }
        ed_pchsPcost.setValue("0");
    }
};

