/**
* method
* @name deleteMarked
* @description
*/
scwin.deleteMarked = function (grdObj, dltObj) {
    let selected = grdObj.getAllFocusedRowIndex();
    selected.sort();
    selected.reverse();
    dltObj.setBroadcast(false);
    for (let idx of selected) {
        if (dltObj.getRowStatus(idx) == "C") {
            dltObj.removeRow(idx);
        } else {
            dltObj.deleteRow(idx);
        }
    }
    dltObj.setBroadcast(true, true);
};

/**
* method
* @name undoMarked
* @description
*/
scwin.undoMarked = function (grdObj, dltObj) {
    let selected = grdObj.getAllFocusedRowIndex();
    selected.sort();
    selected.reverse();
    dltObj.setBroadcast(false);
    for (let idx of selected) {
        if (dltObj.getRowStatus(idx) == "C") {
            dltObj.removeRow(idx);
        } else {
            dltObj.undoRow(idx);
        }
    }
    dltObj.setBroadcast(true, true);
};

/**
* method
* @name wrkIndictClsCdFormatter
* @description
*/
scwin.wrkIndictClsCdFormatter = function (text, formatted, row, col) {
    if (formatted == "") {
        let value = ds_heavyEquipWorkResults.getCellData(row, "wrkIndictClsCd");
        return value;
    }
    return formatted;
};

